-- ============================================================
-- D. FUNCIONES DE APOYO PARA SEED DE AVENTURAS, PASOS Y VARIANTES
-- ============================================================
CREATE OR REPLACE FUNCTION public.hsf_upsert_adventure(
  p_slug text, p_title text, p_intro_text text, p_completion_text text,
  p_reward_title text, p_reward_description text, p_reward_points integer,
  p_min_consumption numeric, p_rotation_weight integer DEFAULT 1
)
RETURNS uuid LANGUAGE plpgsql AS $$
DECLARE v_adventure_id uuid;
BEGIN
  SELECT id INTO v_adventure_id FROM public.hsf_adventures WHERE slug = p_slug;
  IF v_adventure_id IS NULL THEN
    INSERT INTO public.hsf_adventures (slug,title,intro_text,completion_text,reward_title,reward_description,reward_points,min_consumption,rotation_weight,active)
    VALUES (p_slug,p_title,p_intro_text,p_completion_text,p_reward_title,p_reward_description,p_reward_points,p_min_consumption,p_rotation_weight,true)
    RETURNING id INTO v_adventure_id;
  ELSE
    UPDATE public.hsf_adventures SET title=p_title, intro_text=p_intro_text, completion_text=p_completion_text, reward_title=p_reward_title,
      reward_description=p_reward_description, reward_points=p_reward_points, min_consumption=p_min_consumption, rotation_weight=p_rotation_weight,
      active=true, updated_at=now() WHERE id=v_adventure_id;
  END IF;
  RETURN v_adventure_id;
END; $$;

CREATE OR REPLACE FUNCTION public.hsf_upsert_adventure_step(
  p_adventure_slug text, p_step_order integer, p_zone_slug text, p_narrator_name text,
  p_narrator_line text, p_story_text text, p_question text, p_options jsonb,
  p_correct_answer text, p_difficulty text, p_wrong_feedback text, p_correct_feedback text,
  p_clue_to_next_zone text
)
RETURNS uuid LANGUAGE plpgsql AS $$
DECLARE v_adventure_id uuid; v_zone_id uuid; v_step_id uuid;
BEGIN
  SELECT id INTO v_adventure_id FROM public.hsf_adventures WHERE slug = p_adventure_slug;
  IF v_adventure_id IS NULL THEN RAISE EXCEPTION 'No existe aventura con slug: %', p_adventure_slug; END IF;
  SELECT id INTO v_zone_id FROM public.hsf_adventure_zones WHERE slug = p_zone_slug;
  IF v_zone_id IS NULL THEN RAISE EXCEPTION 'No existe zona con slug: %', p_zone_slug; END IF;
  SELECT id INTO v_step_id FROM public.hsf_adventure_steps WHERE adventure_id=v_adventure_id AND step_order=p_step_order ORDER BY created_at ASC LIMIT 1;
  IF v_step_id IS NULL THEN
    INSERT INTO public.hsf_adventure_steps (adventure_id,step_order,required_zone_id,narrator_name,narrator_line,story_text,question,answer_type,options,correct_answer,difficulty,wrong_feedback,correct_feedback,clue_to_next_zone)
    VALUES (v_adventure_id,p_step_order,v_zone_id,p_narrator_name,p_narrator_line,p_story_text,p_question,'multiple_choice',p_options,p_correct_answer,p_difficulty,p_wrong_feedback,p_correct_feedback,p_clue_to_next_zone)
    RETURNING id INTO v_step_id;
  ELSE
    UPDATE public.hsf_adventure_steps SET required_zone_id=v_zone_id, narrator_name=p_narrator_name, narrator_line=p_narrator_line, story_text=p_story_text,
      question=p_question, answer_type='multiple_choice', options=p_options, correct_answer=p_correct_answer, difficulty=p_difficulty,
      wrong_feedback=p_wrong_feedback, correct_feedback=p_correct_feedback, clue_to_next_zone=p_clue_to_next_zone, updated_at=now() WHERE id=v_step_id;
  END IF;
  RETURN v_step_id;
END; $$;

CREATE OR REPLACE FUNCTION public.hsf_seed_step_variant(
  p_adventure_slug text, p_step_order integer, p_variant_key text, p_narrator_line text,
  p_story_text text, p_question text, p_options jsonb, p_correct_answer text,
  p_difficulty text, p_wrong_feedback text, p_correct_feedback text, p_clue_to_next_zone text
)
RETURNS uuid LANGUAGE plpgsql AS $$
DECLARE v_step_id uuid; v_variant_id uuid;
BEGIN
  SELECT s.id INTO v_step_id FROM public.hsf_adventure_steps s JOIN public.hsf_adventures a ON a.id=s.adventure_id
  WHERE a.slug=p_adventure_slug AND s.step_order=p_step_order ORDER BY s.created_at ASC LIMIT 1;
  IF v_step_id IS NULL THEN RAISE EXCEPTION 'No existe paso para aventura %, orden %', p_adventure_slug, p_step_order; END IF;
  INSERT INTO public.hsf_adventure_step_variants (step_id,variant_key,narrator_line,story_text,question,answer_type,options,correct_answer,difficulty,wrong_feedback,correct_feedback,clue_to_next_zone,active)
  VALUES (v_step_id,p_variant_key,p_narrator_line,p_story_text,p_question,'multiple_choice',p_options,p_correct_answer,p_difficulty,p_wrong_feedback,p_correct_feedback,p_clue_to_next_zone,true)
  ON CONFLICT (step_id, variant_key) DO UPDATE SET narrator_line=EXCLUDED.narrator_line, story_text=EXCLUDED.story_text, question=EXCLUDED.question,
    answer_type=EXCLUDED.answer_type, options=EXCLUDED.options, correct_answer=EXCLUDED.correct_answer, difficulty=EXCLUDED.difficulty,
    wrong_feedback=EXCLUDED.wrong_feedback, correct_feedback=EXCLUDED.correct_feedback, clue_to_next_zone=EXCLUDED.clue_to_next_zone, active=true, updated_at=now()
  RETURNING id INTO v_variant_id;
  RETURN v_variant_id;
END; $$;

