SELECT public.hsf_upsert_adventure_step($$aventura-magica-qr$$, 1, $$gran-comedor$$, $$Narrador mágico$$, $$El mapa despierta en la entrada...$$, $$Has entrado a Hogwarts Snacks & Foods. La aventura comienza.$$, $$¿Qué frase activa el Mapa del Merodeador?$$, $$[{"text": "Travesura realizada", "value": "A"}, {"text": "Juro solemnemente que mis intenciones no son buenas", "value": "B"}, {"text": "Expecto Patronum", "value": "C"}, {"text": "Lumos Máxima", "value": "D"}]$$::jsonb, $$B$$, $$media$$, $$El mapa no responde a esa frase.$$, $$Correcto. La tinta empieza a moverse.$$, $$Busca el Gran Comedor.$$);
