SELECT public.hsf_upsert_adventure_step($$banquete_de_los_fantasmas$$, 1, $$gran-comedor$$, $$La mesa sin sombra$$, $$Una silla se mueve sola. Alguien invisible quiere sentarse, pero primero exige una respuesta.$$, $$El banquete inicia con una pregunta sobre la noche en que todo comenzó.$$, $$En la primera película, ¿qué profesor aparece como aparente amenaza durante el partido de Quidditch, aunque la amenaza real era otra?$$, $$[{"text": "Snape", "value": "A"}, {"text": "Flitwick", "value": "B"}, {"text": "Lockhart", "value": "C"}, {"text": "Lupin", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$La silla se aleja. Era una trampa de percepción, no una respuesta simple.$$, $$La silla vuelve a su lugar: entendiste el engaño visual de la escena.$$, $$Sigue al invitado invisible hacia la sala donde el valor suele llegar antes que la prudencia.$$);
SELECT public.hsf_upsert_adventure_step($$banquete_de_los_fantasmas$$, 2, $$gryffindor$$, $$El brindis del león$$, $$Una copa invisible choca contra otra. Nadie la sostiene.$$, $$El fantasma de la torre quiere comprobar si recuerdas quién ganó puntos cuando todo parecía perdido.$$, $$Al final de La Piedra Filosofal, ¿quién recibe puntos por jugar la mejor partida de ajedrez?$$, $$[{"text": "Harry", "value": "A"}, {"text": "Ron", "value": "B"}, {"text": "Hermione", "value": "C"}, {"text": "Neville", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$La copa se queda muda. Esa partida tuvo otro héroe.$$, $$El brindis resuena: Ron merecía ese reconocimiento.$$, $$Busca donde las respuestas no se anuncian en voz alta; se deslizan entre sombras, linajes y medias verdades.$$);
SELECT public.hsf_upsert_adventure_step($$banquete_de_los_fantasmas$$, 3, $$slytherin$$, $$El susurro bajo la mesa$$, $$Un fantasma no identificado atraviesa una pared y deja una frase incompleta.$$, $$Aquí no basta recordar villanos. Hay que distinguir identidades falsas.$$, $$¿Quién se hacía pasar por Ojoloco Moody en El Cáliz de Fuego?$$, $$[{"text": "Lucius Malfoy", "value": "A"}, {"text": "Barty Crouch Jr.", "value": "B"}, {"text": "Peter Pettigrew", "value": "C"}, {"text": "Igor Karkaroff", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$El susurro se corta. Esa identidad no estaba bajo la poción.$$, $$El susurro completa la frase: era Barty Crouch Jr.$$, $$El fantasma dejó una cuenta sin pagar en el lugar donde una broma puede valer más que una reliquia.$$);
SELECT public.hsf_upsert_adventure_step($$banquete_de_los_fantasmas$$, 4, $$callejon-diagon$$, $$La cuenta imposible$$, $$Un pergamino de compras se llena solo con nombres y precios absurdos.$$, $$El callejón quiere saber si reconoces un negocio de bromas por encima de cualquier tienda seria.$$, $$¿Qué gemelos abren una tienda de bromas mágicas?$$, $$[{"text": "Fred y George", "value": "A"}, {"text": "Percy y Charlie", "value": "B"}, {"text": "Dean y Seamus", "value": "C"}, {"text": "Crabbe y Goyle", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$El pergamino explota en confeti inútil. No eran esos.$$, $$El confeti forma dos nombres: Fred y George.$$, $$El último aplauso no viene de una casa de Hogwarts, sino de una zona donde la fantasía también sabe hablar con fantasmas.$$);
SELECT public.hsf_upsert_adventure_step($$banquete_de_los_fantasmas$$, 5, $$disney$$, $$El aplauso invisible$$, $$Se escucha un aplauso suave, como de teatro vacío.$$, $$La pregunta final une fantasmas y memoria.$$, $$¿Cuál fantasma acompaña a la casa Gryffindor en las películas?$$, $$[{"text": "Nick Casi Decapitado", "value": "A"}, {"text": "El Barón Sanguinario", "value": "B"}, {"text": "La Dama Gris", "value": "C"}, {"text": "El Fraile Gordo", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$El teatro se oscurece. Ese fantasma pertenece a otra historia o casa.$$, $$Los aplausos crecen: invitaste al fantasma correcto.$$, $$$$);
SELECT public.hsf_upsert_adventure_step($$copa_de_las_casas_oculta$$, 1, $$gryffindor$$, $$El marcador rojo$$, $$El marcador de Gryffindor marca cero, pero el león no parece preocupado.$$, $$La copa pregunta por una victoria ganada al final, no durante la competencia.$$, $$¿Quién recibe puntos por enfrentarse a sus amigos para intentar detenerlos al final de La Piedra Filosofal?$$, $$[{"text": "Neville", "value": "A"}, {"text": "Ron", "value": "B"}, {"text": "Harry", "value": "C"}, {"text": "Percy", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$El marcador no sube. Ese acto de valentía fue más silencioso.$$, $$El marcador despierta: Neville también fue valiente.$$, $$El marcador no se arregla solo. Busca donde todas las casas pueden ser observadas al mismo tiempo bajo luces imposibles.$$);
SELECT public.hsf_upsert_adventure_step($$copa_de_las_casas_oculta$$, 2, $$gran-comedor$$, $$Los relojes de puntos$$, $$Los relojes de las casas giran sin control.$$, $$Para estabilizarlos, debes recordar una asignatura donde una respuesta brillante importaba mucho.$$, $$¿Qué criatura estudian con Hagrid en El Prisionero de Azkaban y requiere una reverencia antes de acercarse?$$, $$[{"text": "Un thestral", "value": "A"}, {"text": "Un hipogrifo", "value": "B"}, {"text": "Un basilisco", "value": "C"}, {"text": "Un dragón noruego", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$Los relojes siguen girando. Esa criatura exigía otra etiqueta.$$, $$Los relojes se detienen: el hipogrifo aceptó la reverencia.$$, $$Las gemas verdes reclaman turno. Ve donde ganar no siempre significa ser querido, pero sí saber calcular.$$);
SELECT public.hsf_upsert_adventure_step($$copa_de_las_casas_oculta$$, 3, $$slytherin$$, $$El marcador verde$$, $$Las gemas verdes caen una por una como si midieran tu paciencia.$$, $$Slytherin pide una pregunta sobre engaño planeado con frialdad.$$, $$¿Qué personaje usa una poción multijugos para hacerse pasar por Ojoloco Moody?$$, $$[{"text": "Barty Crouch Jr.", "value": "A"}, {"text": "Lucius Malfoy", "value": "B"}, {"text": "Peter Pettigrew", "value": "C"}, {"text": "Gilderoy Lockhart", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$Las gemas se dispersan. Esa mentira tuvo otro rostro.$$, $$El marcador se alinea: la infiltración era de Barty Crouch Jr.$$, $$La copa fue empeñada donde los trucos, las compras y los objetos raros cambian de dueño con demasiada facilidad.$$);
SELECT public.hsf_upsert_adventure_step($$copa_de_las_casas_oculta$$, 4, $$callejon-diagon$$, $$La copa empeñada$$, $$La copa parece estar en venta, pero el precio son datos precisos.$$, $$El callejón pregunta por una tienda donde el caos se volvió negocio.$$, $$¿Cómo se llama la tienda de bromas de Fred y George?$$, $$[{"text": "Sortilegios Weasley", "value": "A"}, {"text": "Bromas Zonko", "value": "B"}, {"text": "Honeydukes", "value": "C"}, {"text": "Artículos Mágicos Black", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$El precio sube. Esa no era su tienda principal en el callejón.$$, $$La etiqueta cambia a vendido: recordaste el nombre correcto.$$, $$El brillo final está donde las victorias no se miden solo en puntos, sino en la emoción de un cuento bien cerrado.$$);
SELECT public.hsf_upsert_adventure_step($$copa_de_las_casas_oculta$$, 5, $$disney$$, $$El marcador dorado$$, $$La copa aparece rodeada de luz cálida.$$, $$La última pregunta es de símbolo: no basta saber magia, hay que entender qué representa ganar.$$, $$¿Qué demuestra la victoria final de Gryffindor en La Piedra Filosofal?$$, $$[{"text": "Que Dumbledore siempre favorece sin razón", "value": "A"}, {"text": "Que el valor, la lógica, la amistad y la lealtad también cuentan", "value": "B"}, {"text": "Que el Quidditch decide todo", "value": "C"}, {"text": "Que Slytherin no tenía puntos reales", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$La copa se aleja. La respuesta era menos burlona y más completa.$$, $$La copa vuelve a su pedestal: comprendiste por qué sumaron esos puntos.$$, $$$$);
SELECT public.hsf_upsert_adventure_step($$hechizo_de_los_suenos_rotos$$, 1, $$disney$$, $$El sueño agrietado$$, $$Una estrella de luz se parte en tres reflejos.$$, $$La primera prueba pregunta por deseo, pero no acepta respuestas cursis al azar.$$, $$¿Qué revela el Espejo de Oesed según la explicación de Dumbledore?$$, $$[{"text": "El futuro exacto", "value": "A"}, {"text": "El deseo más profundo del corazón", "value": "B"}, {"text": "La ubicación de los horrocruxes", "value": "C"}, {"text": "La casa correcta de cada estudiante", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$La estrella se divide más. Ese espejo no predice ni clasifica.$$, $$La estrella se repara un poco: era el deseo profundo.$$, $$El sueño necesita una decisión valiente. Busca donde las huellas avanzan aunque el miedo todavía camine detrás.$$);
SELECT public.hsf_upsert_adventure_step($$hechizo_de_los_suenos_rotos$$, 2, $$gryffindor$$, $$El paso decidido$$, $$Un par de huellas aparece en el suelo y avanza sin dueño.$$, $$La pregunta trata sobre una decisión tomada aun con miedo.$$, $$¿Por qué Harry decide proteger la Piedra Filosofal al final de la primera película?$$, $$[{"text": "Porque quiere ganar puntos", "value": "A"}, {"text": "Porque cree que Snape/Voldemort puede robarla", "value": "B"}, {"text": "Porque se lo ordena Draco", "value": "C"}, {"text": "Porque busca comprar una escoba", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$Las huellas retroceden. Esa motivación no sostiene la escena.$$, $$Las huellas avanzan: Harry creyó que debía impedir el robo.$$, $$La consecuencia de esa decisión espera donde muchas miradas se reúnen y un anuncio puede cambiar el marcador de todos.$$);
SELECT public.hsf_upsert_adventure_step($$hechizo_de_los_suenos_rotos$$, 3, $$gran-comedor$$, $$El aplauso incierto$$, $$El comedor parece esperar un anuncio final.$$, $$La prueba pregunta por reconocimiento, no por fama.$$, $$¿Qué grupo de amigos recibe puntos decisivos al final de La Piedra Filosofal?$$, $$[{"text": "Harry, Ron, Hermione y Neville", "value": "A"}, {"text": "Draco, Crabbe y Goyle", "value": "B"}, {"text": "Fred, George y Percy", "value": "C"}, {"text": "Dean, Seamus y Oliver", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$El comedor guarda silencio. No fue ese grupo.$$, $$El comedor aplaude suavemente: recordaste a los cuatro.$$, $$El objeto tentador no está en una mesa. Está donde las vitrinas prometen más de lo que deberían.$$);
SELECT public.hsf_upsert_adventure_step($$hechizo_de_los_suenos_rotos$$, 4, $$callejon-diagon$$, $$El objeto tentador$$, $$Un objeto dorado aparece en una vitrina y luego se oculta.$$, $$La pregunta distingue objetos poderosos de objetos engañosos.$$, $$¿Cuál de estos objetos pertenece directamente a la búsqueda de la inmortalidad en La Piedra Filosofal?$$, $$[{"text": "La Piedra Filosofal", "value": "A"}, {"text": "El giratiempo", "value": "B"}, {"text": "El Mapa del Merodeador", "value": "C"}, {"text": "La capa de invisibilidad", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$La vitrina se empaña. Ese objeto era de otra historia.$$, $$La vitrina se abre: la piedra era el centro del deseo.$$, $$El último fragmento se esconde donde el deseo, si no se controla, aprende a hablar con voz de ambición.$$);
