SELECT public.hsf_upsert_adventure_step($$legado_de_la_serpiente$$, 1, $$slytherin$$, $$La marca en la piedra$$, $$El piso parece más frío aquí. Una serpiente de luz se enrolla alrededor del QR.$$, $$La voz de la mazmorra no te pide gritar un hechizo: te pide recordar el objeto que guardaba una memoria peligrosa.$$, $$En La Cámara Secreta, ¿qué objeto manipula a Ginny Weasley?$$, $$[{"text": "Un guardapelo", "value": "A"}, {"text": "Un diario", "value": "B"}, {"text": "Una copa", "value": "C"}, {"text": "Una varita rota", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$La piedra se enfría más. Ese objeto no abrió la Cámara.$$, $$La serpiente reconoce la memoria encerrada en el diario.$$, $$Sal de la piedra fría y busca donde todos celebran, pero también donde los rumores pesan más cuando una casa guarda silencio.$$);
