SELECT public.hsf_upsert_adventure_step($$varita_extraviada_del_callejon$$, 1, $$callejon-diagon$$, $$La caja abierta$$, $$Una caja larga permanece abierta y cubierta de polvo brillante.$$, $$La varita pide que recuerdes la conexión más famosa entre dos núcleos.$$, $$¿Qué relación especial tienen las varitas de Harry y Voldemort en las películas?$$, $$[{"text": "Son de la misma madera solamente", "value": "A"}, {"text": "Comparten núcleo de pluma del mismo fénix", "value": "B"}, {"text": "Fueron hechas por Dumbledore", "value": "C"}, {"text": "No tienen ninguna relación", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$La caja se cierra a medias. La conexión era más específica.$$, $$La caja vibra: compartían núcleo de pluma del mismo fénix.$$, $$La chispa salió de la tienda y cayó donde hasta los platos podrían presenciar un duelo silencioso.$$);
SELECT public.hsf_upsert_adventure_step($$varita_extraviada_del_callejon$$, 2, $$gran-comedor$$, $$La chispa entre platos$$, $$Una chispa salta de copa en copa sin quemar nada.$$, $$La pregunta es de hechizo práctico, no de duelo espectacular.$$, $$¿Qué hechizo se usa para atraer objetos hacia quien lo invoca?$$, $$[{"text": "Expelliarmus", "value": "A"}, {"text": "Accio", "value": "B"}, {"text": "Lumos", "value": "C"}, {"text": "Obliviate", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$La chispa se aleja. Ese hechizo no atrae objetos.$$, $$La chispa vuelve a tu mano: Accio era correcto.$$, $$La varita busca una mano valiente: ve donde desarmar puede ser más poderoso que destruir.$$);
SELECT public.hsf_upsert_adventure_step($$varita_extraviada_del_callejon$$, 3, $$gryffindor$$, $$El duelo breve$$, $$Una marca roja aparece como si alguien hubiera practicado defensa.$$, $$La varita pregunta por el hechizo de desarme más reconocible de Harry.$$, $$¿Cuál es el hechizo característico para desarmar a un oponente?$$, $$[{"text": "Expelliarmus", "value": "A"}, {"text": "Avada Kedavra", "value": "B"}, {"text": "Petrificus Totalus", "value": "C"}, {"text": "Wingardium Leviosa", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$La marca se rompe. Ese no era el desarme clásico.$$, $$La marca brilla: el desarme fue reconocido.$$, $$La madera vibra hacia donde la estrategia observa desde la sombra y una orden puede pesar más que un hechizo.$$);
SELECT public.hsf_upsert_adventure_step($$varita_extraviada_del_callejon$$, 4, $$slytherin$$, $$El estuche cerrado$$, $$Un estuche verde se abre apenas, como si desconfiara.$$, $$La pregunta toca una maldición imperdonable, pero sin pedir repetir fórmulas peligrosas fuera de contexto.$$, $$¿Qué maldición intenta resistir Harry durante las clases falsas de Moody en El Cáliz de Fuego?$$, $$[{"text": "La maldición Imperius", "value": "A"}, {"text": "La maldición de lengua trabada", "value": "B"}, {"text": "Un hechizo de levitación", "value": "C"}, {"text": "Un encantamiento de memoria", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$El estuche se cierra. Esa clase era más oscura que eso.$$, $$El estuche cede: recordaste la Imperius.$$, $$La última estrella no pertenece al duelo. Pertenece a un lugar donde la magia se vuelve espectáculo, recuerdo y fotografía.$$);
SELECT public.hsf_upsert_adventure_step($$varita_extraviada_del_callejon$$, 5, $$disney$$, $$La chispa final$$, $$La varita dibuja una estrella antes de volver a su caja.$$, $$La pregunta final busca distinguir intención: una varita no es buena ni mala por sí sola.$$, $$¿Qué idea se repite con fuerza en la relación entre magos y varitas?$$, $$[{"text": "El poder depende solo del objeto", "value": "A"}, {"text": "La elección, intención y vínculo del mago importan", "value": "B"}, {"text": "Las varitas funcionan igual para todos", "value": "C"}, {"text": "Las varitas no tienen historia", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$La estrella se apaga. La varita no era solo herramienta.$$, $$La estrella queda suspendida: entendiste el vínculo.$$, $$$$);
SELECT public.hsf_upsert_adventure_step($$archivo-prohibido-directora$$, 1, $$gran-comedor$$, $$El retrato de la directora$$, $$Un retrato baja la voz: “El archivo no se abre con fuerza, sino con memoria”.$$, $$El Gran Comedor muestra una primera hoja sellada con cera dorada.$$, $$En El Prisionero de Azkaban, ¿quién daña el retrato de la Dama Gorda al intentar entrar a la sala común?$$, $$[{"text": "Remus Lupin", "value": "A"}, {"text": "Peter Pettigrew", "value": "B"}, {"text": "Sirius Black", "value": "C"}, {"text": "Lucius Malfoy", "value": "D"}]$$::jsonb, $$C$$, $$difícil$$, $$El retrato se cierra. Esa no fue la sombra que buscaba la entrada.$$, $$Correcto. El retrato reconoce que recuerdas más que el escándalo.$$, $$El archivo señala la sala donde el valor no siempre grita.$$);
SELECT public.hsf_upsert_adventure_step($$archivo-prohibido-directora$$, 2, $$gryffindor$$, $$La pluma escarlata$$, $$Una pluma escribe sola sobre una hoja rota.$$, $$La pista habla de clases, permisos especiales y una alumna que cargó con más tiempo del que debía.$$, $$¿Qué profesora entrega a Hermione el giratiempo para asistir a más clases?$$, $$[{"text": "Pomona Sprout", "value": "A"}, {"text": "Minerva McGonagall", "value": "B"}, {"text": "Sybill Trelawney", "value": "C"}, {"text": "Madame Hooch", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$La pluma se detiene. No cualquier profesora habría autorizado ese secreto.$$, $$Correcto. El archivo acepta tu precisión.$$, $$Busca donde se compran objetos mágicos y también se esconden primeras impresiones.$$);
SELECT public.hsf_upsert_adventure_step($$archivo-prohibido-directora$$, 3, $$callejon-diagon$$, $$El recibo antiguo$$, $$Un recibo aparece con tinta que cambia de color.$$, $$El Callejón Diagon recuerda el día en que dos rivales se cruzaron antes de entender su destino.$$, $$¿En qué tienda Harry conoce por primera vez a Draco Malfoy en La Piedra Filosofal?$$, $$[{"text": "Ollivanders", "value": "A"}, {"text": "Flourish y Blotts", "value": "B"}, {"text": "Sortilegios Weasley", "value": "C"}, {"text": "Madame Malkin, túnicas para todas las ocasiones", "value": "D"}]$$::jsonb, $$D$$, $$difícil$$, $$El recibo se arruga. Esa tienda no guarda ese primer encuentro.$$, $$Correcto. No todo duelo empieza con varitas.$$, $$La siguiente hoja baja hacia las mazmorras.$$);
