SELECT public.hsf_upsert_adventure_step($$archivo-prohibido-directora$$, 5, $$disney$$, $$El sello de cierre$$, $$Una llave dorada flota sobre el archivo.$$, $$Para cerrar el archivo, debes entender una lección que va más allá de una sola saga.$$, $$¿Qué idea resume mejor la advertencia de Dumbledore sobre el Espejo de Oesed?$$, $$[{"text": "Los espejos siempre muestran el futuro", "value": "A"}, {"text": "Vivir solo mirando deseos puede impedir vivir la realidad", "value": "B"}, {"text": "La magia elimina cualquier pérdida", "value": "C"}, {"text": "Los sueños son pruebas oficiales del Ministerio", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$La llave no gira. El archivo no buscaba una respuesta superficial.$$, $$Correcto. El archivo se cierra con una lección, no con un hechizo.$$, $$Muestra tu pergamino digital al staff para validar tu recompensa.$$);
SELECT public.hsf_upsert_adventure_step($$reliquias-del-banquete-final$$, 1, $$gran-comedor$$, $$La mesa triangular$$, $$Tres marcas aparecen sobre una mesa vacía.$$, $$El banquete exige reconocer el símbolo antes de reclamar cualquier reliquia.$$, $$En el símbolo de las Reliquias de la Muerte, ¿qué representa la línea vertical?$$, $$[{"text": "La Piedra de la Resurrección", "value": "A"}, {"text": "La Capa de Invisibilidad", "value": "B"}, {"text": "La Varita de Saúco", "value": "C"}, {"text": "El Mapa del Merodeador", "value": "D"}]$$::jsonb, $$C$$, $$difícil$$, $$La mesa se oscurece. Esa parte del símbolo no corresponde.$$, $$Correcto. La primera reliquia ha sido reconocida.$$, $$La siguiente marca busca valentía, pero también memoria.$$);
SELECT public.hsf_upsert_adventure_step($$reliquias-del-banquete-final$$, 2, $$gryffindor$$, $$La espada callada$$, $$Una luz roja cae sobre el segundo símbolo.$$, $$La pista habla de una lealtad escondida que solo se entiende al final.$$, $$¿Qué patronus guía a Harry hacia la espada de Gryffindor en Las Reliquias de la Muerte?$$, $$[{"text": "Una cierva", "value": "A"}, {"text": "Un ciervo", "value": "B"}, {"text": "Un lobo", "value": "C"}, {"text": "Un fénix", "value": "D"}]$$::jsonb, $$A$$, $$difícil$$, $$La luz se apaga. No era ese animal el que marcaba la pista.$$, $$Correcto. La cierva revela una verdad que tardó años en entenderse.$$, $$La tercera marca se esconde entre linajes y ambición.$$);
SELECT public.hsf_upsert_adventure_step($$reliquias-del-banquete-final$$, 3, $$slytherin$$, $$El medallón pesado$$, $$Un medallón vibra como si guardara una discusión antigua.$$, $$La reliquia no pregunta por poder, sino por el rastro de un objeto robado.$$, $$¿Quién tenía el guardapelo de Slytherin antes de que llegara a manos de Dolores Umbridge?$$, $$[{"text": "Bellatrix Lestrange", "value": "A"}, {"text": "Fenrir Greyback", "value": "B"}, {"text": "Barty Crouch Jr.", "value": "C"}, {"text": "Mundungus Fletcher", "value": "D"}]$$::jsonb, $$D$$, $$difícil$$, $$El medallón pesa más. Esa no fue la conexión correcta.$$, $$Correcto. El rastro del guardapelo continúa.$$, $$La ruta sube al lugar donde los objetos mágicos tienen precio y secreto.$$);
SELECT public.hsf_upsert_adventure_step($$reliquias-del-banquete-final$$, 4, $$callejon-diagon$$, $$El contrato del duende$$, $$Un contrato aparece firmado con tinta plateada.$$, $$La pista menciona una entrada peligrosa, un banco mágico y una alianza incómoda.$$, $$¿Qué duende ayuda a Harry, Ron y Hermione a entrar a Gringotts?$$, $$[{"text": "Filius", "value": "A"}, {"text": "Griphook", "value": "B"}, {"text": "Bogrod", "value": "C"}, {"text": "Ragnok", "value": "D"}]$$::jsonb, $$B$$, $$difícil$$, $$El contrato se rompe. Ese no fue el guía principal de la entrada.$$, $$Correcto. La alianza fue frágil, pero necesaria.$$, $$El banquete final se cierra donde la fantasía también entiende el sacrificio.$$);
