CREATE OR REPLACE FUNCTION public.hsf_current_adventure_season()
RETURNS TABLE (
  season_number integer,
  season_label text,
  template_order integer,
  season_title text,
  season_subtitle text,
  season_lore text,
  theme_key text,
  accent_hex text,
  starts_on date,
  ends_on date,
  week_number integer,
  day_number integer,
  season_progress numeric
)
LANGUAGE sql STABLE AS $$
  WITH st AS (
    SELECT base_date, season_duration_days FROM public.hsf_adventure_season_settings WHERE id=1 AND active=true
  ), tpl_count AS (
    SELECT GREATEST(COUNT(*) FILTER (WHERE active=true), 1)::integer AS total_templates FROM public.hsf_adventure_season_templates
  ), calc AS (
    SELECT GREATEST((CURRENT_DATE - st.base_date), 0)::integer AS days_elapsed, st.base_date, st.season_duration_days, tpl_count.total_templates FROM st CROSS JOIN tpl_count
  ), season_calc AS (
    SELECT (floor(days_elapsed::numeric / season_duration_days)::integer + 1) AS season_number,
           ((floor(days_elapsed::numeric / season_duration_days)::integer % total_templates) + 1) AS template_order,
           (base_date + (floor(days_elapsed::numeric / season_duration_days)::integer * season_duration_days))::date AS starts_on,
           (base_date + (((floor(days_elapsed::numeric / season_duration_days)::integer + 1) * season_duration_days) - 1))::date AS ends_on,
           ((days_elapsed % season_duration_days) + 1)::integer AS day_number,
           (floor(((days_elapsed % season_duration_days)::numeric) / 7)::integer + 1) AS week_number,
           round((((days_elapsed % season_duration_days) + 1)::numeric / season_duration_days::numeric) * 100, 2) AS season_progress
    FROM calc
  )
  SELECT sc.season_number, 'TEMPORADA ' || sc.season_number::text AS season_label, sc.template_order,
         tpl.title AS season_title, tpl.subtitle AS season_subtitle, tpl.lore_text AS season_lore, tpl.theme_key, tpl.accent_hex,
         sc.starts_on, sc.ends_on, sc.week_number, sc.day_number, sc.season_progress
  FROM season_calc sc JOIN public.hsf_adventure_season_templates tpl ON tpl.template_order=sc.template_order AND tpl.active=true;
$$;

CREATE OR REPLACE VIEW public.hsf_current_adventure_season_view AS SELECT * FROM public.hsf_current_adventure_season();

CREATE OR REPLACE VIEW public.hsf_current_season_adventure_schedule AS
SELECT cs.season_number, cs.season_label, cs.template_order, cs.season_title, cs.season_subtitle, cs.season_lore, cs.theme_key, cs.accent_hex,
       cs.starts_on, cs.ends_on, cs.week_number, cs.day_number, cs.season_progress,
       sta.unlock_week, sta.display_order, sta.featured, sta.active AS season_adventure_active,
       a.id AS adventure_id, a.slug, a.title, a.intro_text, a.completion_text, a.reward_title, a.reward_description, a.reward_points, a.min_consumption, a.rotation_weight, a.active AS adventure_active,
       CASE WHEN sta.unlock_week <= cs.week_number THEN true ELSE false END AS is_unlocked,
       CASE WHEN sta.unlock_week <= cs.week_number THEN 'DISPONIBLE' ELSE 'BLOQUEADA' END AS unlock_status
FROM public.hsf_current_adventure_season() cs
JOIN public.hsf_adventure_season_template_adventures sta ON sta.template_order=cs.template_order
JOIN public.hsf_adventures a ON a.id=sta.adventure_id
WHERE sta.active=true AND a.active=true
  AND NOT EXISTS (
    SELECT 1 FROM public.hsf_adventure_steps s JOIN public.hsf_adventure_zones z ON z.id=s.required_zone_id
    WHERE s.adventure_id=a.id AND z.active=false
  )
ORDER BY sta.featured DESC, sta.unlock_week ASC, sta.display_order ASC, a.title ASC;

CREATE OR REPLACE VIEW public.hsf_current_season_available_adventures AS
SELECT * FROM public.hsf_current_season_adventure_schedule WHERE is_unlocked=true;

CREATE OR REPLACE FUNCTION public.hsf_assign_run_step_variants(p_run_id uuid)
RETURNS void LANGUAGE plpgsql AS $$
BEGIN
  INSERT INTO public.hsf_adventure_run_step_variants (run_id, step_id, variant_id)
  SELECT p_run_id, s.id AS step_id, chosen_variant.id AS variant_id
  FROM public.hsf_adventure_runs r
  JOIN public.hsf_adventure_steps s ON s.adventure_id = r.adventure_id
  LEFT JOIN LATERAL (
    SELECT v.id FROM public.hsf_adventure_step_variants v
    WHERE v.step_id=s.id AND v.active=true
    ORDER BY md5(p_run_id::text || '-' || s.id::text || '-' || v.id::text)
    LIMIT 1
  ) chosen_variant ON true
  WHERE r.id=p_run_id
  ON CONFLICT (run_id, step_id) DO NOTHING;
END;
$$;

CREATE OR REPLACE VIEW public.hsf_adventure_run_steps_resolved AS
SELECT r.id AS run_id, r.customer_id, r.adventure_id, r.current_step_order, r.last_scanned_step_order, r.status AS run_status,
       a.slug AS adventure_slug, a.title AS adventure_title,
       s.id AS step_id, s.step_order, s.required_zone_id,
       z.slug AS zone_slug, z.name AS zone_name, z.floor_number, z.qr_token, z.poster_title, z.poster_subtitle,
       rv.variant_id,
       COALESCE(v.narrator_line, s.narrator_line) AS narrator_line,
       COALESCE(v.story_text, s.story_text) AS story_text,
       COALESCE(v.question, s.question) AS question,
       COALESCE(v.answer_type, s.answer_type) AS answer_type,
       COALESCE(v.options, s.options) AS options,
       COALESCE(v.correct_answer, s.correct_answer) AS correct_answer,
       COALESCE(v.difficulty, s.difficulty) AS difficulty,
       COALESCE(v.wrong_feedback, s.wrong_feedback) AS wrong_feedback,
       COALESCE(v.correct_feedback, s.correct_feedback) AS correct_feedback,
       COALESCE(v.clue_to_next_zone, s.clue_to_next_zone) AS clue_to_next_zone
FROM public.hsf_adventure_runs r
JOIN public.hsf_adventures a ON a.id=r.adventure_id
JOIN public.hsf_adventure_steps s ON s.adventure_id=r.adventure_id
JOIN public.hsf_adventure_zones z ON z.id=s.required_zone_id
LEFT JOIN public.hsf_adventure_run_step_variants rv ON rv.run_id=r.id AND rv.step_id=s.id
LEFT JOIN public.hsf_adventure_step_variants v ON v.id=rv.variant_id
WHERE z.active=true
ORDER BY r.id, s.step_order;

CREATE OR REPLACE VIEW public.hsf_active_adventure_zones AS
SELECT id, slug, name, floor_number, description, qr_token, poster_title, poster_subtitle, active, created_at, updated_at
FROM public.hsf_adventure_zones WHERE active=true
ORDER BY floor_number ASC NULLS LAST, name ASC;

