)
INSERT INTO public.hsf_adventure_season_template_adventures (template_order, adventure_id, unlock_week, display_order, featured, active)
SELECT seed.template_order, a.id, seed.unlock_week, seed.display_order, seed.featured, true
FROM seed JOIN public.hsf_adventures a ON a.slug=seed.adventure_slug
ON CONFLICT (template_order, adventure_id) DO UPDATE SET unlock_week=EXCLUDED.unlock_week, display_order=EXCLUDED.display_order, featured=EXCLUDED.featured, active=true, updated_at=now();

-- ============================================================
-- J. REASIGNAR HISTÓRICOS QUE HAYAN INICIADO EN ZONAS EXTRA
-- ============================================================
WITH zone_redirects(old_slug, new_slug) AS (
  VALUES
    ('entrada-principal','gran-comedor'),('hufflepuff','gryffindor'),('ravenclaw','slytherin'),
    ('aulas-magicas','callejon-diagon'),('cabana-hagrid','gryffindor'),('bosque-prohibido','slytherin'),
    ('sala-menesteres','disney'),('torre-magica','disney')
)
UPDATE public.hsf_adventure_runs r
SET started_zone_id = new_zone.id, updated_at = now()
FROM public.hsf_adventure_zones old_zone
JOIN zone_redirects zr ON zr.old_slug=old_zone.slug
JOIN public.hsf_adventure_zones new_zone ON new_zone.slug=zr.new_slug
WHERE r.started_zone_id=old_zone.id;

COMMIT;

